parameters.jsCode:
// Filtrer les RDV avec un client ayant un telephone et/ou un email
const rdvs = items[0].json || [];
const results = [];

for (const rdv of rdvs) {
  if (!rdv.clients) continue;
  const client = rdv.clients;
  if (!client.phone && !client.email) continue;

  const start = new Date(rdv.start_time);
  const dateStr = start.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
  const timeStr = start.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

  // Normaliser telephone francais au format international
  let phone = (client.phone || '').replace(/[\s.-]/g, '');
  if (phone.startsWith('0')) phone = '+33' + phone.substring(1);
  else if (phone && !phone.startsWith('+')) phone = '+33' + phone;

  results.push({
    json: {
      rdv_id: rdv.id,
      user_id: rdv.user_id,
      client_id: rdv.client_id,
      client_first_name: client.first_name,
      client_name: `${client.first_name} ${client.last_name}`,
      client_phone: phone,
      client_email: client.email,
      has_phone: !!phone,
      has_email: !!client.email,
      rdv_title: rdv.title,
      rdv_date: dateStr,
      rdv_time: timeStr,
      rdv_location: rdv.location || 'A confirmer',
      agent_name: (rdv.profiles && rdv.profiles.full_name) || 'Alison',
      agent_business: (rdv.profiles && rdv.profiles.business_name) || 'Visit & Smile',
      sms_text: `Bonjour ${client.first_name}, je vous rappelle notre RDV demain ${dateStr} a ${timeStr} - ${rdv.title}${rdv.location ? ' a ' + rdv.location : ''}. A demain ! Alison - Visit & Smile`
    }
  });
}

return results;

